class TestProfile(Enum):
    QUICK = "quick"        # lint + typecheck のみ（30秒以内）
    STANDARD = "standard"  # lint + typecheck + unit tests
    FULL = "full"          # lint + typecheck + unit + integration + build
    CI = "ci"              # CI/CD パイプライン用（全部 + カバレッジ）


# プロファイル別のステップ定義
PROFILES = {
