def run_step(step_name: str, cwd: str = ".") -> dict:
    """個別テストステップを実行"""
    step_config = COMMANDS.get(step_name)
    if not step_config:
        return {"step": step_name, "status": "skip", "reason": "未定義"}

    cmd = step_config["cmd"]
    timeout = step_config["timeout"]

    # コマンドの存在確認
    if not shutil.which(cmd[0]):
        fallback = step_config.get("fallback_cmd")
        if fallback and shutil.which(fallback[0]):
            cmd = fallback
        else:
            return {
                "step": step_name,
                "status": "skip",
                "reason": f"{cmd[0]} 未インストール",
            }

    # build は特殊処理（全 .py ファイルをコンパイルチェック）
    if step_name == "build":
        return _run_build_check(cwd)

    try:
        result = subprocess.run(
            cmd, capture_output=True, text=True,
            cwd=cwd, timeout=timeout,
        )
        # 最小情報だけ返す（失敗時）
        if result.returncode != 0:
            error_lines = result.stdout.split("\n")[-10:]
            stderr_lines = result.stderr.split("\n")[-5:]
            return {
                "step": step_name,
                "status": "fail",
                "exit_code": result.returncode,
                "summary": "\n".join(error_lines + stderr_lines).strip()[:500],
            }

        return {
            "step": step_name,
            "status": "pass",
            "exit_code": 0,
        }

    except subprocess.TimeoutExpired:
        return {
            "step": step_name,
            "status": "timeout",
            "timeout_seconds": timeout,
        }
    except Exception as e:
        return {
            "step": step_name,
            "status": "error",
            "error": str(e)[:200],
        }


def _run_build_check(cwd: str) -> dict:
    """全 .py ファイルの構文チェック"""
    errors = []
    py_files = list(Path(cwd).rglob("*.py"))

    for f in py_files:
        try:
            result = subprocess.run(
                ["python", "-m", "py_compile", str(f)],
                capture_output=True, text=True, timeout=10,
            )
            if result.returncode != 0:
                errors.append(f"{f.name}: {result.stderr.strip()[:100]}")
        except Exception:
            pass

    if errors:
        return {
            "step": "build",
            "status": "fail",
            "errors": errors[:10],
            "total_files": len(py_files),
        }

    return {
        "step": "build",
        "status": "pass",
        "total_files": len(py_files),
    }


