def _read_audit_logs(log_type: str, limit: int = 20) -> dict:
    """JSONL ログファイルを読み取って返す"""
    log_dir = LOG_DIRS.get(log_type)
    if not log_dir or not log_dir.exists():
        return {"log_type": log_type, "entries": [], "count": 0}

    entries = []
    for f in sorted(log_dir.glob("*.jsonl"), reverse=True):
        with open(f) as fh:
            for line in fh:
                line = line.strip()
                if line:
                    try:
                        entries.append(json.loads(line))
                    except json.JSONDecodeError:
                        pass
        if len(entries) >= limit:
            break

    entries = entries[:limit]
    return {"log_type": log_type, "entries": entries, "count": len(entries)}


def _audit_summary() -> dict:
    """全ログのサマリ"""
    summary = {}
    for log_type, log_dir in LOG_DIRS.items():
        if not log_dir.exists():
            summary[log_type] = {"count": 0, "latest": None}
            continue

        count = 0
        latest = None
        for f in sorted(log_dir.glob("*.jsonl"), reverse=True):
            with open(f) as fh:
                for line in fh:
                    line = line.strip()
                    if line:
                        count += 1
                        if latest is None:
                            try:
                                entry = json.loads(line)
                                latest = entry.get("timestamp", "unknown")
                            except json.JSONDecodeError:
                                pass

        summary[log_type] = {"count": count, "latest": latest}

    return {
        "timestamp": datetime.now().isoformat(),
        "logs": summary,
        "total_entries": sum(v["count"] for v in summary.values()),
    }


